class Solution {
    private static final int MOD = (int) (1e9 + 7);
    public int numberOfStableArrays(int zero, int one, int limit) {
        long[][][] dp = new long[2][zero + 1][one + 1];
        dp[0][1][0] = 1;
        dp[1][0][1] = 1;
        for (int i = 0; i <= limit; i++) {
            for (int j = 1; j <= zero; j++) {
                for (int k = 1; k <= one; k++) {
                    if (i > 0) {
                        dp[0][j][k] = (dp[0][j][k] + dp[1][j][k]) % MOD;
                        dp[1][j][k] = (dp[1][j][k] + dp[0][j][k]) % MOD;
                    }
                    if (j < zero) {
                        dp[0][j + 1][k] = (dp[0][j + 1][k] + dp[0][j][k]) % MOD;
                    }
                    if (k < one) {
                        dp[1][j][k + 1] = (dp[1][j][k + 1] + dp[1][j][k]) % MOD;
                    }
                }
            }
        }
        long res = 0;
        for (int i = 0; i <= limit; i++) {
            res = (res + dp[0][zero][one] + dp[1][zero][one]) % MOD;
        }
        return (int) res;
    }
}
